bouldering:[{group:"Rock surface",tags:["Dry","Damp","Humid/greasy","Perfect friction"]},{group:"Landing",tags:["Good landing","Uneven landing","Wet ground"]},{group:"Sun & temps",tags:["Sunny","Shady","Cold/crispy","Too warm"]},{group:"Approach & access",tags:["Approach dry","Approach muddy","Approach snowy","Road/trailhead open","Road/trailhead closed"]},{group:"General",tags:["Quiet","Crowded","Buggy"]},{group:"Hazards",hazard:true,tags:["Rockfall observed","Bad landing zone"]}],
