function distMiles(a,b){const R=3958.8,dLat=(b.lat-a.lat)*Math.PI/180,dLon=(b.lng-a.lng)*Math.PI/180;const x=Math.sin(dLat/2)**2+Math.cos(a.lat*Math.PI/180)*Math.cos(b.lat*Math.PI/180)*Math.sin(dLon/2)**2;return R*2*Math.atan2(Math.sqrt(x),Math.sqrt(1-x));}
function gn(g){const m=g&&g.match(/5\.(\d+)([a-d]?)/);return m?parseInt(m[1])+("abcd".indexOf(m[2])+1)/4:6;}
const trustOf=(p)=>{if(!p)return 0;return Math.max(0,Math.min(100,Math.round(trustFactors(p).reduce(function(acc,f){return acc+(f.pts||0);},0))));};
function compat(a,b){let s=20;s+=(a.disciplines.filter(x=>b.disciplines.includes(x)).length)*16;const g2=g=>{const m=g&&g.match(/5\.(\d+)([a-d]?)/);return m?parseInt(m[1])*4+("abcd".indexOf(m[2])+1):0;};s+=Math.max(0,28-Math.abs(g2(a.sportGrade)-g2(b.sportGrade))*3);s+=(a.objectiveIds.filter(x=>b.objectiveIds.includes(x)).length)*14;if(b.verified)s+=8;const sd=Math.abs((a.hikingSpeedFtHr||1000)-(b.hikingSpeedFtHr||1000));s+=Math.max(0,10-Math.floor(sd/100));const _ao=availOf(a),_bo=availOf(b);const _shA=_ao.filter(x=>x!=="flexible"&&_bo.indexOf(x)>=0).length;s+=Math.min(12,_shA*6);return Math.min(99,Math.max(s,20));}
function scarfHrs(distKm,gainM,lossM,fit,packKg){const fm={beginner:{sx:3.5,sy:400,sz:600},intermediate:{sx:4.8,sy:600,sz:800},advanced:{sx:5.5,sy:750,sz:900},expert:{sx:6.5,sy:900,sz:1000}};const f=fm[fit]||fm.intermediate;const pp=packKg>15?0.85:packKg>8?0.92:1;return(distKm/(f.sx*pp))+(gainM/(f.sy*pp))+(lossM/(f.sz*pp));}
function techHrs(pitches,len,gradeNum,anchor){
  if(!pitches)return 0;
  const speed=130*Math.exp(-0.11*(gradeNum-5)); // m/hr of pitch progress, incl. belaying the follower; slower as grade rises
  let perPitch=0.17+(len/speed);                 // ~10 min belay transition + climb time
  if(gradeNum<=6.5)perPitch*=0.5;                // easy terrain (≤5.6) is usually simul-climbed / moved together, not pitched
  return pitches*perPitch;
}
function buildConsensus(activity,voteFor){if(!activity||!activity.length)return null;const trustOf=n=>{const a=n===ME.name?ME:CLIMBERS.find(c=>c.name===n);return a?a.trustScore:50;};const wOf=n=>0.45+0.55*(trustOf(n)/100);const byMonth={};activity.forEach(a=>{if(!a.date)return;const mo=new Date(a.date).getMonth();if(!byMonth[mo])byMonth[mo]={count:0,stars:0};byMonth[mo].count++;byMonth[mo].stars+=a.stars||0;});const avgStars=activity.reduce((s,a)=>s+(a.stars||0),0)/activity.length;const allTags={};let wTot=0;activity.forEach(a=>{const w=wOf(a.user);wTot+=w;(a.condTags||[]).forEach(t=>{allTags[t]=(allTags[t]||0)+w;});});const topTags=Object.entries(allTags).sort((a,b)=>b[1]-a[1]).slice(0,5).map(([t,w])=>({tag:t,pct:Math.min(100,Math.round(w/wTot*100))}));const bestMonths=Object.entries(byMonth).filter(([,v])=>v.stars/v.count>=4).map(([m])=>MONTHS[parseInt(m)]);const confidence=activity.length>=5?"high":activity.length>=3?"medium":"low";const recentReports=activity.filter(a=>isRecent(a.date)).sort((a,b)=>(b.date||"").localeCompare(a.date||""));const rTags={};let rTot=0;recentReports.forEach(a=>{const w=wOf(a.user);rTot+=w;(a.condTags||[]).forEach(t=>{rTags[t]=(rTags[t]||0)+w;});});const recentTags=rTot?Object.entries(rTags).sort((a,b)=>b[1]-a[1]).slice(0,5).map(([t,w])=>({tag:t,pct:Math.min(100,Math.round(w/rTot*100))})):[];const clearedTag=t=>{if(!voteFor)return false;const v=voteFor(t);return !!(v&&v.gone>=2&&v.gone>(v.still||0));};const hazards=recentReports.filter(a=>(a.condTags||[]).some(t=>HAZARD_TAGS.has(t)&&!clearedTag(t))).map(a=>({user:a.user,avatar:a.avatar,date:a.date,trust:trustOf(a.user),tags:(a.condTags||[]).filter(t=>HAZARD_TAGS.has(t)&&!clearedTag(t))})).slice(0,4);const clearedTags=voteFor?[...new Set(recentReports.flatMap(a=>(a.condTags||[]).filter(t=>HAZARD_TAGS.has(t)&&clearedTag(t))))]:[];const lastDate=activity.map(a=>a.date).filter(Boolean).sort().slice(-1)[0]||null;const verifiedCount=activity.filter(a=>{const au=a.user===ME.name?ME:CLIMBERS.find(c=>c.name===a.user);return au&&au.verified;}).length;return{avgStars,topTags,bestMonths,byMonth,confidence,reportCount:activity.length,hazards,clearedTags,lastDate,verifiedCount,recentTags,recentCount:recentReports.length};}
