function datesAgreed(c){if(!c)return false;const ds=(c.dates&&c.dates.length)?c.dates:(c.date?[c.date]:[]);if(!ds.length)return false;const need=[...new Set([0,...(c.members||[]).filter(m=>m.status==="confirmed").map(m=>m.climberId)])];if(c.dayAcks){return ds.some(d=>{const a=c.dayAcks[d]||[];return need.every(id=>a.includes(id));});}const a=c.dateAcks||[];return need.every(id=>a.includes(id));}
function relTime(ts){if(!ts)return "";var d=Date.now()-ts;var m=Math.floor(d/60000);if(m<1)return "now";if(m<60)return m+"m";var h=Math.floor(m/60);if(h<24)return h+"h";var dy=Math.floor(h/24);if(dy===1)return "yesterday";if(dy<7)return dy+"d";return new Date(ts).toLocaleDateString(undefined,{month:"short",day:"numeric"});}
function agreedDate(c){if(!c)return null;const ds=(c.dates&&c.dates.length)?c.dates:(c.date?[c.date]:[]);if(!ds.length)return null;const need=[...new Set([0,...(c.members||[]).filter(m=>m.status==="confirmed").map(m=>m.climberId)])];if(c.dayAcks){const g=ds.find(d=>{const a=c.dayAcks[d]||[];return need.every(id=>a.includes(id));});return g||null;}const a=c.dateAcks||[];return need.every(id=>a.includes(id))?ds[0]:null;}
function daysUntil(ds){if(!ds)return null;try{const t=new Date();t.setHours(0,0,0,0);const d=new Date(ds+"T12:00:00");return Math.round((d-t)/86400000);}catch(e){return null;}}
function futLabel(ds){const n=daysUntil(ds);if(n==null)return "";return n<0?"past":n===0?"today":n===1?"tomorrow":"in "+n+" days";}
function gearReadout(route,owners){
  const disc=catOf(route);const base=(DISC_GEAR[disc]||[]).slice();
  const text=(((route&&route.rack)||[]).join(" ")+" "+(((route&&route.gearTiers&&route.gearTiers.required)||[]).join(" "))).toLowerCase();
  GEAR_CATS.forEach(c=>{if(c.kw.some(k=>text.includes(k))&&base.indexOf(c.label)<0)base.push(c.label);});
  const owned=(owners||[]).map(g=>(g||[]).join(" ").toLowerCase());
  return base.map(label=>{const c=GEAR_CATS.find(x=>x.label===label)||{kw:[label.toLowerCase()]};return {label:label,have:owned.some(t=>c.kw.some(k=>t.includes(k)))};});
}
function RouteGearCheck({route,onSeeReports,rack,onSaveRack}){const [rackEdit,setRackEdit]=useState(null);const items=gearReadout(route,[]);const cams=(route&&route.cams)||[];if(!items.length&&!cams.length)return null;const _gbX=((route.activity)||[]).filter(function(a){return a&&a.gearBeta;}).map(function(a){return {who:a.user,avatar:a.avatar,date:a.date,note:a.gearBeta};});const beta=_gbX.concat((route.gearBeta&&route.gearBeta.length)?route.gearBeta:(((route.activity)||[]).filter(function(a){return a&&a.text&&/(\bcams?\b|\brack\b|doubles|#\d|\bnuts?\b|draws|quickdraw|\bropes?\b|screws|pickets|\bset of\b)/i.test(a.text);}).slice(0,3).map(function(a){return {who:a.user,avatar:a.avatar,date:a.date,note:a.text};})));return <div style={{background:C.card,borderRadius:12,padding:"12px 14px",border:`1px solid ${C.border}`,marginTop:12}}><div style={{fontSize:13,fontWeight:700,marginBottom:3,color:C.text}}>What to bring</div><div style={{fontSize:12,color:C.textMuted,marginBottom:10,lineHeight:1.45}}>The rack and kit this climb calls for.</div>{(rack&&rack.length)||onSaveRack?<div style={{marginBottom:11,paddingBottom:11,borderBottom:`1px solid ${C.borderLight}`}}><div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:7}}><span style={{fontSize:11.5,fontWeight:800,color:C.blue,textTransform:"uppercase",letterSpacing:0.4}}>Detailed rack</span>{onSaveRack?<button onClick={()=>setRackEdit(rackEdit==null?(rack||[]).join("\n"):null)} style={{fontSize:11.5,fontWeight:700,color:rackEdit==null?C.blue:C.textMuted,background:"none",border:"none",cursor:"pointer",padding:0}}>{rackEdit==null?"Edit":"Cancel"}</button>:null}</div>{rackEdit==null?<div style={{display:"flex",flexDirection:"column",gap:5}}>{(rack||[]).map((gi,i)=><div key={i} style={{display:"flex",gap:8,fontSize:12.5,color:C.text,lineHeight:1.45}}><span style={{color:C.blue,flexShrink:0}}>•</span><span>{gi}</span></div>)}</div>:<div><textarea value={rackEdit} onChange={e=>setRackEdit(e.target.value)} rows={7} placeholder="One item per line — e.g. Cams — single #0.3–#3" style={{width:"100%",boxSizing:"border-box",padding:"9px 11px",borderRadius:9,border:"1px solid "+C.border,background:C.surface,color:C.text,fontSize:13,lineHeight:1.5,outline:"none",resize:"vertical",fontFamily:"inherit"}}/><button onClick={()=>{onSaveRack((rackEdit||"").split("\n").map(s=>s.trim()).filter(Boolean));setRackEdit(null);}} style={{marginTop:8,padding:"8px 14px",background:C.blue,color:"#fff",border:"none",borderRadius:9,fontSize:13,fontWeight:700,cursor:"pointer"}}>Save rack</button></div>}</div>:null}{cams.length?<div style={{marginBottom:10,paddingBottom:10,borderBottom:`1px solid ${C.borderLight}`}}><div style={{fontSize:11.5,fontWeight:700,color:C.textSub,marginBottom:6}}>Trad rack — cam sizes (one set, reused each pitch)</div><div style={{display:"flex",gap:5,flexWrap:"wrap"}}>{cams.map(function(z){return <span key={z} style={{padding:"3px 9px",borderRadius:7,fontSize:12,fontWeight:700,background:C.blueBg,color:C.blue,border:`1px solid ${C.blueDim}`}}>{camFmt(z)}</span>;})}</div></div>:null}{items.map(function(x,i){return <div key={i} style={{display:"flex",alignItems:"center",gap:8,padding:"5px 0",borderBottom:i<items.length-1?`1px solid ${C.borderLight}`:"none"}}><span style={{width:14,textAlign:"center",fontSize:14,color:C.blue}}>·</span><span style={{fontSize:13,color:C.text,flex:1}}>{x.label}</span></div>;})}{(function(){const pd=route.pitchDetail||[];const bolts=pd.reduce(function(s2,p){return s2+(p.bolts||0);},0);const maxB=pd.reduce(function(m,p){return Math.max(m,p.bolts||0);},0);const np=route.pitches||pd.length||1;const disc=catOf(route);const ns={marginTop:11,paddingTop:10,borderTop:"1px solid "+C.borderLight,fontSize:11.5,color:C.textSub,lineHeight:1.5};if(disc==="sport")return <div style={ns}>{bolts>0?(""+bolts+" bolts"+(np>1?(" across "+np+" pitches"):"")+" — bring about "+(maxB+2)+" quickdraws"+(np>1?(" (most-bolted pitch has "+maxB+"; reuse them each pitch)"):" (bolts plus the anchor)")+"."):"Bring quickdraws for the most-bolted pitch plus two for the anchor, and reuse them every pitch."}</div>;return null;})()}{beta.length?<div style={{marginTop:11,paddingTop:10,borderTop:`1px solid ${C.borderLight}`}}><div style={{fontSize:11.5,fontWeight:700,color:C.textSub,marginBottom:7}}>Gear beta from recent parties</div>{beta.map(function(b,i){return <div key={i} style={{display:"flex",gap:8,marginBottom:8}}>{b.avatar?<Av src={b.avatar} size={24}/>:null}<div style={{flex:1,minWidth:0}}><div style={{fontSize:11.5,color:C.textMuted,marginBottom:1}}>{(b.who||"A climber")+(b.date?" · "+b.date:"")}</div><div style={{fontSize:12.5,color:C.text,lineHeight:1.5,fontStyle:"italic"}}>{"“"+b.note+"”"}</div></div></div>;})}{onSeeReports?<button onClick={onSeeReports} style={{marginTop:2,padding:"7px 12px",background:C.surface,border:`1px solid ${C.border}`,borderRadius:9,color:C.blue,fontSize:12,fontWeight:700,cursor:"pointer"}}>Read full trip reports →</button>:null}</div>:null}</div>;}

