const Av=({src,size,online})=>{const sz=size||36;const d=Math.max(9,Math.round(sz*0.28));return <span style={{position:"relative",display:"inline-block",flexShrink:0,width:sz,height:sz,lineHeight:0}}><img src={src} alt="" style={{width:sz,height:sz,borderRadius:"50%",objectFit:"cover",border:"2px solid "+C.border,display:"block"}} onError={onImgErr(FALLBACK_AV)}/>{online?<span title="Online now" className="cm-pulse" style={{position:"absolute",bottom:0,right:0,width:d,height:d,background:C.green,borderRadius:"50%",border:"2px solid "+C.card,boxSizing:"border-box"}}></span>:null}</span>;};
const Stars=({n,size})=><span style={{color:C.amber,fontSize:size||14}}>{"★".repeat(Math.round(n))}{"".repeat(5-Math.round(n))}</span>;
