const GH=({children})=><div style={{fontSize:14,fontWeight:800,color:C.text,letterSpacing:0.3,paddingTop:12,paddingBottom:11,marginBottom:13,borderBottom:`1px solid ${C.borderLight}`,display:"flex",alignItems:"center",gap:9}}><span style={{width:3,height:14,borderRadius:2,background:C.blue,display:"inline-block"}}></span>{children}</div>;
