const Bar=({val,max,color,h})=><div style={{background:C.border,borderRadius:3,overflow:"hidden",height:h||6}}><div style={{width:`${Math.min(100,(val/(max||100))*100)}%`,height:"100%",background:color||C.blue,borderRadius:3,transition:"width .4s"}}/></div>;
const EMOJI_ICON={"":"crews","":"crews","":"shield","📍":"pin","":"flag","":"alert","":"alert","":"mountain","":"mountain","":"mountain","":"doc","":"doc","":"doc","":"calendar","":"chat","":"megaphone","":"check","":"download","":"link","":"map","":"explore","":"search","":"target","":"award","":"award","":"bell","":"camera","":"camera","":"bulb","":"bulb","":"chart","":"settings","":"log","":"log","":"flag","":"download"};
function Lbl({s,size}){var str=String(s);var m=str.match(/^([\u2190-\u2BFF\u{1F000}-\u{1FAFF}\uFE0F\u200D]+)\s*([\s\S]*)$/u);if(!m)return str;var key=m[1].replace(/[\uFE0F\u200D]/g,"");var nm=EMOJI_ICON[key];if(!nm)return str;return <span style={{display:"inline-flex",alignItems:"center",gap:6,verticalAlign:"middle"}}><ActionIcon name={nm} size={size||14} color="currentColor"/>{m[2]}</span>;}
function notifIcon(n){var s=((((n&&n.text)||"")+" "+((n&&n.tab)||""))).toLowerCase();if(/kudos/.test(s))return "award";if(/vouch/.test(s))return "shield";if(/report|trip|climbed/.test(s))return "doc";if(/crew/.test(s))return "crews";if(/friend|request/.test(s))return "user";return "bell";}
function ActionIcon({name,color,size}){const s=size||19;const p={width:s,height:s,viewBox:"0 0 24 24",fill:"none",stroke:color||"currentColor",strokeWidth:2,strokeLinecap:"round",strokeLinejoin:"round"};if(name==="explore")return <svg {...p}><circle cx="12" cy="12" r="10"/><polygon points="16.24 7.76 14.12 14.12 7.76 16.24 9.88 9.88 16.24 7.76"/></svg>;if(name==="partners")return <svg {...p}><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><line x1="19" y1="8" x2="19" y2="14"/><line x1="22" y1="11" x2="16" y2="11"/></svg>;if(name==="crews")return <svg {...p}><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>;if(name==="log")return <svg {...p}><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.12 2.12 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>;if(name==="target")return <svg {...p}><circle cx="12" cy="12" r="9"/><circle cx="12" cy="12" r="5"/><circle cx="12" cy="12" r="1.5"/></svg>;if(name==="pin")return <svg {...p}><path d="M20 10c0 6-8 12-8 12s-8-6-8-12a8 8 0 0 1 16 0z"/><circle cx="12" cy="10" r="2.5"/></svg>;if(name==="home")return <svg {...p}><path d="M3 9.5 12 3l9 6.5V20a1 1 0 0 1-1 1h-5v-6H9v6H4a1 1 0 0 1-1-1z"/></svg>;if(name==="user")return <svg {...p}><circle cx="12" cy="8" r="4"/><path d="M5.5 21a6.5 6.5 0 0 1 13 0"/></svg>;if(name==="mountain")return <svg {...p}><path d="m8 3 4 8 5-5 5 15H2L8 3z"/></svg>;if(name==="alert")return <svg {...p}><path d="M10.3 3.9 1.8 18a2 2 0 0 0 1.7 3h17a2 2 0 0 0 1.7-3L13.7 3.9a2 2 0 0 0-3.4 0z"/><line x1="12" y1="9" x2="12" y2="13.5"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>;if(name==="calendar")return <svg {...p}><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>;if(name==="chat")return <svg {...p}><path d="M21 11.5a8.4 8.4 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.4 8.4 0 0 1-3.8-.9L3 21l1.9-5.7a8.4 8.4 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.4 8.4 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8z"/></svg>;if(name==="megaphone")return <svg {...p}><path d="m3 11 18-5v12L3 14z"/><path d="M11.6 16.8a3 3 0 1 1-5.8-1.6"/></svg>;if(name==="check")return <svg {...p}><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>;if(name==="download")return <svg {...p}><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>;if(name==="link")return <svg {...p}><path d="M10 13a5 5 0 0 0 7.5.5l3-3a5 5 0 0 0-7-7l-1.7 1.6"/><path d="M14 11a5 5 0 0 0-7.5-.5l-3 3a5 5 0 0 0 7 7l1.7-1.6"/></svg>;if(name==="map")return <svg {...p}><polygon points="1 6 1 22 8 18 16 22 23 18 23 2 16 6 8 2 1 6"/><line x1="8" y1="2" x2="8" y2="18"/><line x1="16" y1="6" x2="16" y2="22"/></svg>;if(name==="search")return <svg {...p}><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>;if(name==="flag")return <svg {...p}><path d="M4 15s1-1 4-1 5 2 8 2 4-1 4-1V3s-1 1-4 1-5-2-8-2-4 1-4 1z"/><line x1="4" y1="22" x2="4" y2="15"/></svg>;if(name==="camera")return <svg {...p}><path d="M23 19a2 2 0 0 1-2 2H3a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h4l2-3h6l2 3h4a2 2 0 0 1 2 2z"/><circle cx="12" cy="13" r="3.5"/></svg>;if(name==="bulb")return <svg {...p}><path d="M9 18h6"/><path d="M10 22h4"/><path d="M12 2a7 7 0 0 0-4 12.7c.6.5 1 1.3 1 2.3h6c0-1 .4-1.8 1-2.3A7 7 0 0 0 12 2z"/></svg>;if(name==="chart")return <svg {...p}><line x1="18" y1="20" x2="18" y2="10"/><line x1="12" y1="20" x2="12" y2="4"/><line x1="6" y1="20" x2="6" y2="14"/></svg>;if(name==="settings")return <svg {...p}><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 1 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-4 0v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 1 1-2.83-2.83l.06-.06a1.65 1.65 0 0 0 .33-1.82 1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1 0-4h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 1 1 2.83-2.83l.06.06a1.65 1.65 0 0 0 1.82.33H9a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 4 0v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 1 1 2.83 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82V9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 0 4h-.09a1.65 1.65 0 0 0-1.51 1z"/></svg>;if(name==="bell")return <svg {...p}><path d="M18 8a6 6 0 1 0-12 0c0 7-3 9-3 9h18s-3-2-3-9"/><path d="M13.7 21a2 2 0 0 1-3.4 0"/></svg>;if(name==="doc")return <svg {...p}><path d="M14 3v4a1 1 0 0 0 1 1h4"/><path d="M17 21H7a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h7l5 5v11a2 2 0 0 1-2 2z"/><line x1="9" y1="14" x2="15" y2="14"/><line x1="9" y1="17.5" x2="13" y2="17.5"/></svg>;if(name==="award")return <svg {...p}><circle cx="12" cy="8" r="6"/><path d="M8.5 13.2 7.5 22l4.5-2.6L16.5 22l-1-8.8"/></svg>;if(name==="shield")return <svg {...p}><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/><path d="m9 11.5 2 2 4-4"/></svg>;return null;}
function DiscBadge({id,sm}){const d=CAT[id]||DISC[id];if(!d)return null;return <Pill icon={<DiscIcon d={id} size={sm?11:13}/>} label={d.label} color={d.color} bg={d.bg} sm={sm}/>;}
function TrustBadge({score,compact}){const col=score>=90?C.green:score>=70?C.blue:score>=50?C.amber:C.red;const bg=score>=90?C.greenBg:score>=70?C.blueBg:score>=50?C.amberBg:C.redBg;const lbl=score>=90?"Highly Trusted":score>=70?"Trusted":score>=50?"Building Trust":"New";return <span title="Trust score (0–100): built from ID verification, partner vouches, belay catches logged, climbs logged and certifications. Higher means more proven." style={{display:"inline-flex",verticalAlign:"middle"}}><Pill icon={<ActionIcon name="shield" size={11} color={col}/>} label={compact?`${score}`:`${score} — ${lbl}`} color={col} bg={bg} sm/></span>;}
const VERIF={verified:{label:"Verified",icon:"✓",color:C.green,bg:C.greenBg},community:{label:"Community",icon:"",color:C.blue,bg:C.blueBg},unverified:{label:"Unverified",icon:"",color:C.amber,bg:C.amberBg}};
function VerifyBadge({v,sm}){const t=VERIF[(v||{}).status]||VERIF.unverified;return <Pill label={`${t.icon} ${t.label}`} color={t.color} bg={t.bg} sm={sm}/>;}
function ProvenancePanel({route,onSuggestFix}){const v=route.verif||{status:"unverified"};const [confirmed,setConfirmed]=useState(false),[msg,setMsg]=useState(null);const note=v.status==="verified"?"Cross-checked against an authoritative source and confirmed by multiple climbers.":v.status==="community"?"Added from a public source with some community confirmation — help verify it.":"Single or unconfirmed source. Treat the specifics with caution and verify in the field.";const n=(v.confirms||0)+(confirmed?1:0);return <div style={{background:C.card,borderRadius:12,padding:"12px 14px",border:`1px solid ${C.border}`,marginBottom:12}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:9}}><div style={{fontSize:12,fontWeight:700,color:C.blue}}>DATA CONFIDENCE</div><VerifyBadge v={v}/></div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:9}}><div style={{background:C.surface,borderRadius:9,padding:"8px 10px"}}><div style={{fontSize:12,color:C.textMuted,fontWeight:700,marginBottom:2}}>SOURCE</div><div style={{fontSize:13,color:C.textSub,lineHeight:1.4}}>{v.source||"Unsourced"}</div></div><div style={{background:C.surface,borderRadius:9,padding:"8px 10px"}}><div style={{fontSize:12,color:C.textMuted,fontWeight:700,marginBottom:2}}>LAST UPDATED</div><div style={{fontSize:13,color:C.textSub}}>{v.updated||"—"}</div></div></div><div style={{fontSize:12,color:C.textSub,marginBottom:6}}>{n>0?`${n} climber${n!==1?"s":""} confirmed this data is accurate.`:"No community confirmations yet."}</div><div style={{fontSize:12,color:C.textMuted,lineHeight:1.5,marginBottom:10}}>{note}</div>{msg?<div style={{background:C.greenBg,borderRadius:9,padding:"9px 11px",border:`1px solid ${C.greenDim}`,fontSize:13,color:C.green,fontWeight:600,textAlign:"center"}}>{msg}</div>:<div style={{display:"flex",gap:7}}><button onClick={()=>{setConfirmed(true);setMsg("✓ Thanks — your confirmation was recorded.");}} style={{flex:1,padding:8,background:C.greenBg,color:C.green,border:`1px solid ${C.greenDim}`,borderRadius:9,fontSize:13,cursor:"pointer",fontWeight:600}}>✓ Confirm accurate</button><button onClick={()=>onSuggestFix&&onSuggestFix()} style={{flex:1,padding:8,background:C.surface,color:C.textSub,border:`1px solid ${C.border}`,borderRadius:9,fontSize:13,cursor:"pointer"}}>Suggest a fix</button></div>}</div>;}
function RiskBadge({id,sm}){const r=RISK_LEVELS.find(x=>x.id===id);if(!r)return <Pill label="Not set" color={C.textMuted} bg={C.surface} sm={sm}/>;return <Pill label={`${r.icon} ${r.label}`} color={r.color} bg={r.bg} sm={sm}/>;}

