function GearSynth({route,partner}){const base=DISC_GEAR[catOf(route)]||[];if(!base.length)return null;return <div style={{background:C.surface,borderRadius:10,padding:"10px 12px",border:`1px solid ${C.border}`}}><div style={{fontSize:12,fontWeight:700,color:C.text,marginBottom:5}}>Gear for {route.name}</div><div style={{fontSize:13,color:C.textSub,lineHeight:1.55}}>{base.join(" · ")}</div></div>;}
