  const set=k=>e=>setForm(f=>({...f,[k]:e.target.value}));const planText="FLOAT PLAN — "+(form.route||"climb")+"\n"+"Partner: "+(form.partner||"—")+"\n"+"Party size: "+(form.party||"—")+"\n"+"Vehicle: "+(form.vehicle||"—")+"\n"+"Trailhead/parking: "+(form.lot||"—")+"\n"+"Depart: "+(form.depart||"—")+"\n"+"Turnaround (turn back regardless): "+(form.turn||"—")+"\n"+"HARD RETURN: "+(form.ret||"—")+"\n"+"Comms plan: "+(form.comms||"—")+"\n"+(coords?("Objective coords: "+coords.lat.toFixed(4)+", "+coords.lng.toFixed(4)+(coords.name?" ("+coords.name+")":"")+"\n"):"")+"Emergency contact: "+(form.contact||"—")+"\n"+(form.notes?("Notes: "+form.notes+"\n"):"")+"If not back by the hard return time, call 911 and ask for county Search and Rescue — give them this plan and the coordinates.";
