const GMETA={g1:{languages:["English","Spanish"],respond:"Usually replies within a few hours",repeat:62,cancel:"A deposit of about half the day rate holds your date; the balance is due the morning of the climb. Cancel 14+ days out and the deposit becomes a reschedule credit; inside 14 days it is forfeited; inside 48 hours or a no-show is the full fee, since Marcus turns away other work to hold your day. If Marcus calls it for weather or unsafe rock, you choose a free reschedule or a full refund."},g2:{languages:["English"],respond:"Usually replies within a day",repeat:55,cancel:"A 35% deposit secures your dates; the balance is due 45 days out. Cancel 45+ days ahead for a refund less the deposit; inside 45 days there is no refund or reschedule. If Dana stands the climb down for weather or conditions, you are offered a reschedule or a refund of fees not already committed to permits and logistics."},g3:{languages:["English","Spanish"],respond:"Usually replies within a few hours",repeat:48,cancel:"A small deposit holds your date and the balance is due on the day. Full refund 7+ days out; inside 7 days the deposit is held as a reschedule credit; inside 48 hours or a no-show is charged in full. A weather call by Tomás means a free reschedule or a full refund."},g4:{languages:["English","Hindi"],respond:"Usually replies within a day",repeat:58,cancel:"A 40% deposit secures your dates; the balance is due 7 days prior. Refund of the balance 14+ days out (deposit held as a credit); inside 14 days no refund. Weather or unsafe sandstone is Priya’s call — rescheduled free or refunded."},g5:{languages:["English","Swedish"],respond:"Usually replies within a day",repeat:51,cancel:"A 35% deposit secures your dates; the balance is due 45 days out. Cancel 45+ days ahead for a refund less the deposit; inside 45 days no refund. If Erik stands the route down for weather or avalanche conditions, you get a reschedule or a refund of fees not already spent."},g6:{languages:["English","Italian"],respond:"Usually replies within a few hours",repeat:67,cancel:"A 30% deposit secures your dates; the balance is due 30 days out. Cancel 30+ days ahead for a refund less the deposit; inside 30 days no refund or reschedule. Weather days are Sofia’s call and are rescheduled when the calendar allows."},g7:{languages:["English"],respond:"Usually replies within a day",repeat:60,cancel:"A 35% deposit secures your glacier dates; the balance is due 60 days out. Cancel 60+ days ahead for a refund less the deposit; inside 60 days no refund. Glacier and weather conditions are Sierra’s call — she reschedules within the season when she can."}};
