  const [areaBy,setAreaBy]=useState("near"),[radiusMi,setRadiusMi]=useState(99999),[areaCountry,setAreaCountry]=useState("usa"),[areaState,setAreaState]=useState(""),[areaId,setAreaId]=useState("");
  const [sortBy,setSortBy]=useState("match"),[showFilters,setShowFilters]=useState(true),[discF,setDiscF]=useState("All"),[whenF,setWhenF]=useState("any"),[minTrust,setMinTrust]=useState(0);
  const fmt=d=>{if(!d)return"Flexible dates";try{return new Date(d+"T12:00:00").toLocaleDateString(DLOCALE,{weekday:"short",month:"short",day:"numeric"});}catch(e){return d;}};
  const cap1=x=>x?x.charAt(0).toUpperCase()+x.slice(1):x;
  const rOf=oc=>ROUTES.find(x=>x.id===oc.routeId)||{};const mtOf=oc=>MOUNTAINS.find(m=>m.id===rOf(oc).mountainId)||{};
  const distOf=oc=>{const mt=mtOf(oc);return (mt&&mt.lat!=null&&ME.lat!=null)?distMiles(ME,mt):null;};
  const now=new Date();const today0=new Date(now.getFullYear(),now.getMonth(),now.getDate());
  const within=(d,months)=>{if(!d)return false;const dt=new Date(d+"T12:00:00");const lim=new Date(now);lim.setMonth(lim.getMonth()+months);return dt>=today0&&dt<=lim;};
  const climbMatches=climbQ.trim()?ROUTES.filter(r=>(r.name+" "+((MOUNTAINS.find(m=>m.id===r.mountainId)||{}).name||"")).toLowerCase().includes(climbQ.trim().toLowerCase())).slice(0,8):[];
