        <div style={{marginBottom:14}}><SL>Readiness Defaults</SL><div style={{fontSize:12,color:C.textMuted,marginBottom:9,lineHeight:1.5}}>Set once here — your crews auto-fill from these, and your risk tolerance feeds crew alignment.</div><div style={{display:"flex",gap:6,marginBottom:10}}>{RISK_LEVELS.map(r=>{const on=meAnswers&&meAnswers.riskTolerance===r.id;return <button key={r.id} onClick={()=>{ME.riskTolerance=r.id;setMeAnswers(a=>({...(a||{}),riskTolerance:r.id}));showToast("Risk tolerance saved");}} style={{flex:1,padding:"9px 6px",borderRadius:11,border:`1.5px solid ${on?r.color:C.border}`,background:on?r.bg:C.card,color:on?r.color:C.textSub,cursor:"pointer",fontSize:12,fontWeight:600}}>{r.icon} {r.label}</button>;})}</div><div style={{background:C.card,borderRadius:10,padding:"4px 12px",border:`1px solid ${C.border}`}}><div style={{display:"flex",justifyContent:"space-between",padding:"7px 0",borderBottom:`1px solid ${C.borderLight}`}}><span style={{fontSize:12,color:C.textMuted}}>Emergency contact</span><span style={{fontSize:12,color:C.textSub,fontWeight:600}}>{ME.emergencyContact}</span></div><div style={{display:"flex",justifyContent:"space-between",padding:"7px 0"}}><span style={{fontSize:12,color:C.textMuted}}>Vehicle</span><span style={{fontSize:12,color:C.textSub,fontWeight:600}}>{ME.vehicle}</span></div></div></div>
